def remaining_time(self):
    """Estimated remaining time in seconds, or None."""
    if self.total is None or self.total == 0:
        return None
    elapsed = self._time() - self.start_t
    if elapsed <= 0 or self.n <= 0:
        return None
    rate = self.n / elapsed
    remaining = (self.total - self.n) / rate
    return remaining
